function setERC165(bytes4[] calldata interfaceIds, bytes4[] calldata interfaceIdsToRemove) external {
    LibDiamond.DiamondStorage storage ds = LibDiamond.diamondStorage();

    ds.supportedInterfaces[type(IERC165).interfaceId] = true;

    for (uint256 i = 0; i < interfaceIds.length; i++) {
        ds.supportedInterfaces[interfaceIds[i]] = true;
    }

    for (uint256 i = 0; i < interfaceIdsToRemove.length; i++) {
        ds.supportedInterfaces[interfaceIdsToRemove[i]] = false;
    }
}

addHits = (aHits, bHits) => {
  if (typeof aHits === "number" && typeof bHits === "number") {
    return aHits + bHits;
  } else if (Array.isArray(aHits) && Array.isArray(bHits)) {
    return aHits.map((a, i) => (a || 0) + (bHits[i] || 0));
  }
  return null;
}

function getTransactionLink(
  txHash: string,
  browserURL?: string,
): string | undefined {
  if (browserURL === undefined) {
    return undefined;
  }

  return `\x1b]8;;${browserURL}/tx/${txHash}\x1b\\ (🔗 view on block explorer)\x1b]8;;\x1b\\`;
}

function getYParity(v: number): number {
  if (v === 27 || v === 28) {
    return v - 27;
  }

  if (v === 0 || v === 1) {
    return v;
  }

  if (v >= 35) {
    return (v - 35) % 2;
  }

  assertHardhatInvariant(false, `Unexpected "v" value: ${v}`);
}

create(name, cfg) {
  cfg = cfg || {};
  let Cons;
  try {
    Cons = require(path.join(__dirname, "lib", name, "index.cjs"));
  } catch (e) {
    if (e.code !== "MODULE_NOT_FOUND") {
      throw e;
    }

    Cons = require(name);
  }

  return new Cons(cfg);
}

#getSimilarStrings(
  stringToCompare: string,
  otherStrings: Iterable<string>,
  maxEditDistance: number = EDIT_DISTANCE_THRESHOLD,
): string[] {
  return [...otherStrings]
    .map((s) => [s, editDistance(s, stringToCompare)] as const)
    .sort(([_, d1], [__, d2]) => d1 - d2)
    .filter(([_, d]) => d <= maxEditDistance)
    .map(([s]) => s);
}

#normaliseErrorPathToNetworkConfig(
  path: Array<string | number>,
  resolvedNetworkName: string,
): Array<string | number> {
  if (path[0] !== undefined && path[0] === "networks") {
    path = path.slice(1);
  }

  if (path[0] !== undefined && path[0] === resolvedNetworkName) {
    path = path.slice(1);
  }

  return path;
}

public getRootsUserSourceNameMap(): Record<string, string> {
  return Object.fromEntries(
    [...this.getRoots().entries()]
      .map(([userSourceName, root]) => [userSourceName, root.inputSourceName])
      .sort(([userSourceName1, _], [userSourceName2, __]) =>
        userSourceName1.localeCompare(userSourceName2),
      ),
  );
}

function hardhatChainTypeToEdrChainType(chainType: ChainType): string {
  if (chainType === OPTIMISM_CHAIN_TYPE) {
    return EDR_OP_CHAIN_TYPE;
  }

  if (chainType === L1_CHAIN_TYPE) {
    return EDR_L1_CHAIN_TYPE;
  }

  return EDR_GENERIC_CHAIN_TYPE;
}
